<?php
 namespace WPAICG\Chat\Admin\Ajax\Traits; use WP_Error; if (!defined('ABSPATH')) { exit; } trait Trait_SendWPError { protected function send_wp_error(WP_Error $error) { $error_data_for_json_response = [ 'message' => $error->get_error_message(), 'code' => $error->get_error_code(), ]; $wp_error_internal_data = $error->get_error_data(); $status_code = isset($wp_error_internal_data['status']) && is_int($wp_error_internal_data['status']) ? $wp_error_internal_data['status'] : 400; wp_send_json_error($error_data_for_json_response, $status_code); } }